def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base = 60 + np.sqrt(cap) * 30 - np.log1p(usage * 8) * 20
        adjustment = 0.0
        if usage > 5:
            base += 6000 * usage ** 1.2
            if cap > 15:
                base += 150 * np.cbrt(cap) + 45 * np.sin(cap * 0.9)
            else:
                base -= 50 * usage
            for i in range(1, 6):
                adjustment += ((-1) ** (i)) * np.cos(usage * np.pi * i * 0.75) * 25 / i
            if cap % 3 < 1:
                adjustment += 45 * np.tan(cap / 12)
        elif 4 < usage <= 5:
            delta = usage - 4
            base += 2500 * delta ** 2 + 220 * np.sqrt(1 - delta)
            for j in range(1, 9):
                adjustment += np.sin(usage * np.pi * (j ** 1.25)) * 30 / j
            if int(cap * 4) % 5 < 2:
                base += 50 * np.cos(cap * 4)
        elif 3 < usage <= 4:
            base += 1500 * (usage - 3) ** 2.5
            for k in range(1, 14):
                val = usage ** k
                if val < 0.3:
                    adjustment += val * 15 / k
                    if k % 6 == 0:
                        adjustment += 7 * k
                else:
                    adjustment += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        adjustment += 30
            if cap % 3.7 < 0.6:
                base += 40 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base += 1100 * (usage - 2) ** 3
            for m in range(1, 16):
                pwr = usage ** m
                if pwr < 0.7:
                    adjustment += pwr * 35 / m
                    if m % 2 == 0:
                        adjustment -= 3 * m
                else:
                    adjustment += (1 - pwr) * 17 / (m + 2)
                    if m == 13 and usage > 2.7:
                        adjustment += 18
            if cap % 2.6 < 0.4:
                base += 38 * np.cos(cap * 2.3)
        elif 1 < usage <= 2:
            base += 800 * (usage - 1) ** 3.5
            for n in range(1, 20):
                power = usage ** n
                if power < 0.8:
                    adjustment += power * 28 / n
                    if n % 3 == 2:
                        adjustment -= 5 * n
                else:
                    adjustment += (1 - power) * 14 / (n + 1)
                    if n == 17 and usage > 1.8:
                        adjustment += 20
            if cap % 1.8 < 0.35:
                base += 30 * np.sin(cap * 1.9)
        elif 0.4 < usage <= 1:
            base += 140 * (1 - usage) ** 1.5
            for o in range(1, 13):
                pwr = usage ** o
                adjustment += (np.tanh(pwr * np.pi / 5) - 0.25) * 15 / o
                if usage < 0.08 * o:
                    adjustment -= 9 * o
            if cap < 0.1:
                base += np.sqrt(cap) * 300
            elif cap < 0.8:
                base += np.log1p(cap * 18) * 40
            else:
                base += (cap % 7) * 28
        else:
            base += 350 * (1 - usage) ** 3
            for p in range(1, 20):
                pwr = usage ** p
                adjustment += (np.sin(pwr * np.pi / 7) - 0.2) * 16 / p
                if usage < 0.012 * p:
                    adjustment -= 15 * p
            if cap < 0.01:
                base += np.sqrt(cap) * 350
            elif cap < 1.2:
                base += np.log1p(cap * 28) * 50
            else:
                base += (cap % 8) * 35
        priority = base + adjustment
        if cap < 0.03:
            priority += 90
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 70
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 0.75:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.22:
                priority -= 40
            for r in range(1, 7):
                if int(cap * 1400) % (r + 5) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 50
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.93:
                priority += 110
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 40
        proximity_score = 0
        if int(cap * 3000) % 21 == 0:
            proximity_score += 18
        if int(cap * 1100) % 25 == 0:
            proximity_score -= 14
        if int(cap * 200) % 11 == 0:
            proximity_score += 16
        for u in range(1, 10):
            diff = abs(usage - u / 10)
            if diff < 0.015:
                proximity_score += 22 / u
            elif diff < 0.04:
                proximity_score += 13 / u
            else:
                proximity_score -= 5 / u
        for v in range(1, 9):
            mod_check = int(cap * 1800) % (v + 11)
            if mod_check == 0:
                proximity_score += v * 6
            elif mod_check == 4:
                proximity_score -= v * 5
        for w in range(1, 6):
            mod_check = int(usage * 1800) % (w + 7)
            if mod_check == 0:
                proximity_score += 12 * w
            elif mod_check == 4:
                proximity_score -= 8 * w
        priority += proximity_score
        if usage < 0.003:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 14
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 3000) % 25 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 700) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
